<?php
namespace App\Domain\Loans\Actions;
use App\Domain\Payouts\Actions\CreatePayout;use App\Enums\LoanApplicationStatus;use App\Enums\LoanStatus;use App\Enums\PayoutType;use App\Enums\VerificationStatus;use App\Models\Loan;use App\Models\LoanApplication;use Illuminate\Support\Facades\Crypt;use Illuminate\Support\Facades\DB;use Illuminate\Support\Str;use Illuminate\Validation\ValidationException;
class DisburseLoan{public function __construct(private CreatePayout $payouts){}public function execute(LoanApplication $application,array $data):Loan{return DB::transaction(function()use($application,$data){$application=LoanApplication::query()->with(['member','product','assessments'])->lockForUpdate()->findOrFail($application->id);if($application->status!==LoanApplicationStatus::Approved)throw ValidationException::withMessages(['status'=>['Only approved applications can be disbursed.']]);if($application->loan()->exists())throw ValidationException::withMessages(['application'=>['A disbursement has already been created.']]);$bankAccount=$application->member->bankAccounts()->whereKey($data['bank_account_id']??$application->preferred_bank_account_id)->first();if(!$bankAccount||$bankAccount->verification_status!==VerificationStatus::Verified)throw ValidationException::withMessages(['bank_account_id'=>['A verified bank account owned by the applicant is required.']]);$assessment=$application->assessments->sortByDesc('assessed_at')->first();$schedule=$assessment->schedule_preview;$charges=$assessment->charge_preview;$added=collect($charges)->where('treatment','add_to_balance')->sum('amount_minor');$deducted=collect($charges)->where('treatment','deduct_from_disbursement')->sum('amount_minor');$repayable=$schedule['repayable_minor']+$added;$loan=Loan::query()->create(['loan_application_id'=>$application->id,'member_id'=>$application->member_id,'loan_product_id'=>$application->loan_product_id,'loan_number'=>'LN-'.strtoupper(Str::ulid()),'principal_minor'=>$application->requested_principal_minor,'interest_minor'=>$schedule['interest_minor'],'charges_added_minor'=>$added,'repayable_minor'=>$repayable,'outstanding_minor'=>$repayable,'status'=>LoanStatus::PendingDisbursement,'disbursed_at'=>$data['disbursement_date'],'maturity_date'=>collect($schedule['installments'])->last()['due_date']]);foreach($charges as $charge)$loan->charges()->create(['charge_id'=>$charge['charge_id'],'name'=>$charge['name'],'treatment'=>$charge['treatment'],'amount_minor'=>$charge['amount_minor'],'snapshot'=>$charge]);$count=count($schedule['installments']);$chargeBase=$count?intdiv($added,$count):0;$allocatedCharges=0;foreach($schedule['installments'] as $index=>$row){$installmentCharge=$index===$count-1?$added-$allocatedCharges:$chargeBase;$allocatedCharges+=$installmentCharge;$loan->installments()->create(['installment_number'=>$row['installment_number'],'due_date'=>$row['due_date'],'principal_due_minor'=>$row['principal_minor'],'interest_due_minor'=>$row['interest_minor'],'charges_due_minor'=>$installmentCharge,'status'=>'upcoming']);}$this->payouts->execute(['member_id'=>$application->member_id,'payable_type'=>Loan::class,'payable_id'=>$loan->id,'idempotency_key'=>'loan-disbursement-'.$application->id,'type'=>PayoutType::LoanDisbursement,'currency'=>$data['currency']??'NGN','amount_minor'=>$application->requested_principal_minor-$deducted,'beneficiary_name'=>$bankAccount->account_name,'bank_code'=>$bankAccount->bank_code,'account_number'=>Crypt::decryptString($bankAccount->account_number_encrypted),'metadata'=>['gross_principal_minor'=>$application->requested_principal_minor,'deducted_charges_minor'=>$deducted,'member_bank_account_id'=>$bankAccount->id]]);return $loan->load(['installments','charges']);});}}
